Future<bool> _ensureDriverLocationPermissionForTrigger(
  BuildContext context,
  User user, {
  required LocationPermissionPromptTrigger trigger,
  required String deniedMessage,
  required String readFailureMessage,
  required String requestFailureMessage,
}) async {
  final promptPolicy =
      await _shouldPromptLocationPermissionForUserUseCase.execute(
    ShouldPromptLocationPermissionForUserCommand(
      uid: user.uid,
      trigger: trigger,
    ),
  );
  final shouldPrompt = promptPolicy.shouldPrompt;

  // 322D: yolcu/misafir rolde konum izni diyalogu hic acilmaz.
  if (!shouldPrompt || kIsWeb) {
    return true;
  }

  if (defaultTargetPlatform == TargetPlatform.iOS) {
    try {
      final result = await _iosLocationPermissionOrchestrator
          .ensureWhileInUseAtValueMoment();
      if (result == IosWhileInUsePermissionResult.granted ||
          result == IosWhileInUsePermissionResult.notApplicable) {
        return true;
      }
    } catch (_) {
      if (context.mounted) {
        _showInfo(context, requestFailureMessage);
      }
      _mobileTelemetry.track(
        eventName: MobileEventNames.permissionDenied,
        category: 'permission',
        addBreadcrumb: true,
        attributes: <String, Object?>{
          'trigger': trigger.name,
          'platform': 'ios',
          'reason': 'request_error',
        },
      );
      return false;
    }

    if (context.mounted) {
      _showInfo(context, deniedMessage);
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.permissionDenied,
      category: 'permission',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'trigger': trigger.name,
        'platform': 'ios',
        'reason': 'user_denied',
      },
    );
    return false;
  }

  if (defaultTargetPlatform != TargetPlatform.android) {
    return true;
  }

  PermissionStatus status;
  try {
    status = await Permission.locationWhenInUse.status;
  } catch (_) {
    if (context.mounted) {
      _showInfo(context, readFailureMessage);
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.permissionDenied,
      category: 'permission',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'trigger': trigger.name,
        'platform': 'android',
        'reason': 'read_error',
      },
    );
    return false;
  }

  if (status.isGranted || status.isLimited) {
    return true;
  }

  try {
    status = await Permission.locationWhenInUse.request();
  } catch (_) {
    if (context.mounted) {
      _showInfo(context, requestFailureMessage);
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.permissionDenied,
      category: 'permission',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'trigger': trigger.name,
        'platform': 'android',
        'reason': 'request_error',
      },
    );
    return false;
  }

  if (status.isGranted || status.isLimited) {
    return true;
  }

  if (context.mounted) {
    _showInfo(context, deniedMessage);
  }
  _mobileTelemetry.track(
    eventName: MobileEventNames.permissionDenied,
    category: 'permission',
    addBreadcrumb: true,
    attributes: <String, Object?>{
      'trigger': trigger.name,
      'platform': 'android',
      'reason': 'user_denied',
    },
  );
  return false;
}
